SELECT id, user_id, password, name, phone, gender, age, height, weight, activity_level, purpose
FROM user_table
WHERE id = #{id}

SELECT id, user_id, password, name, phone, gender, age, height, weight, activity_level, purpose
FROM user_table
WHERE user_id = #{userId}

SELECT id, user_id, password, name, phone, gender, age, height, weight, activity_level, purpose
FROM user_table
WHERE phone = #{phone}

SELECT id, user_id, password, name, phone, gender, age, height, weight, activity_level, purpose
FROM user_table
WHERE name = #{name}
  AND phone = #{phone}

SELECT id, user_id, password, name, phone, gender, age, height, weight, activity_level, purpose
FROM user_table
WHERE user_id = #{userId}
  AND name = #{name}
  AND phone = #{phone}

mapper.update:
UPDATE user_table
SET password = #{password}
WHERE id = #{id}
